// ---------------------------------------------------------------------------
// Application token definitions (speculative/frontier — not in tokens.js)
// ---------------------------------------------------------------------------
const APPLICATION_TOKENS = {
  appear: {
    description: 'Element appearing from below — tooltip, toast, modal.',
    animation: { opacity: [0, 1], transform: ['translateY(8px)', 'translateY(0)'] },
    transition: { duration: 400, easing: [0, 0, 0.2, 1] },
  },
  dismiss: {
    description: 'Element leaving — toast auto-dismiss, modal close.',
    animation: { opacity: [1, 0], transform: ['translateY(0)', 'translateY(8px)'] },
    transition: { duration: 100, easing: [0.4, 0, 1, 1] },
  },
  expand: {
    description: 'Container growing — accordion, drawer, disclosure.',
    animation: { scaleY: [0, 1], opacity: [0, 1] },
    transition: { duration: 200, easing: [0, 0, 0.2, 1] },
    note: 'Applies transform-origin: top. Use on wrapper, not content.',
  },
  focus: {
    description: 'Focus ring appearing — keyboard navigation.',
    animation: { outlineOffset: ['0px', '3px'], opacity: [0, 1] },
    transition: { duration: 100, easing: [0.4, 0, 0.2, 1] },
  },
  celebration: {
    description: 'Expressive confirmation — task completed, achievement unlocked.',
    animation: { transform: ['scale(1)', 'scale(1.15)', 'scale(1)'] },
    transition: { duration: 400, easing: [0.2, 0, 0, 1] },
    note: 'spring.config.bouncy preferred on native platforms. CSS fallback uses emphasize easing.',
  },
};

// ---------------------------------------------------------------------------
// Shared styles
// ---------------------------------------------------------------------------
const baseStyles = `
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f8f8; }

  .page { max-width: 960px; margin: 0 auto; padding: 48px 32px; }
  .page-title { font-size: 13px; font-weight: 600; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px; }
  .page-subtitle { font-size: 20px; font-weight: 700; color: #111; margin-bottom: 8px; }
  .page-description { font-size: 14px; color: #555; line-height: 1.5; margin-bottom: 40px; }
`;

// ---------------------------------------------------------------------------
// Per-token animation executors
// Each returns a Promise that resolves when the animation completes.
// ---------------------------------------------------------------------------
function runAnimation(name, card) {
  const token = APPLICATION_TOKENS[name];
  const { duration, easing } = token.transition;
  const bezier = `cubic-bezier(${easing.join(', ')})`;

  switch (name) {
    case 'appear':
      card.style.opacity = '0';
      card.style.transform = 'translateY(8px)';
      return card.animate(
        [
          { opacity: 0, transform: 'translateY(8px)' },
          { opacity: 1, transform: 'translateY(0)' },
        ],
        { duration, easing: bezier, fill: 'forwards' }
      ).finished;

    case 'dismiss':
      card.style.opacity = '1';
      card.style.transform = 'translateY(0)';
      return card.animate(
        [
          { opacity: 1, transform: 'translateY(0)' },
          { opacity: 0, transform: 'translateY(8px)' },
        ],
        { duration, easing: bezier, fill: 'forwards' }
      ).finished.then(() => {
        // Restore after exit so it's visible again
        card.animate([{ opacity: 1, transform: 'translateY(0)' }], { duration: 1, fill: 'forwards' });
      });

    case 'expand': {
      card.style.transformOrigin = 'top';
      card.style.transform = 'scaleY(0)';
      card.style.opacity = '0';
      return card.animate(
        [
          { transform: 'scaleY(0)', opacity: 0 },
          { transform: 'scaleY(1)', opacity: 1 },
        ],
        { duration, easing: bezier, fill: 'forwards' }
      ).finished;
    }

    case 'focus':
      card.style.outline = '2px solid #007755';
      card.style.outlineOffset = '0px';
      card.style.opacity = '0.5';
      return card.animate(
        [
          { outlineOffset: '0px', opacity: 0.5 },
          { outlineOffset: '3px', opacity: 1 },
        ],
        { duration, easing: bezier, fill: 'forwards' }
      ).finished;

    case 'celebration':
      card.style.transform = 'scale(1)';
      return card.animate(
        [
          { transform: 'scale(1)' },
          { transform: 'scale(1.15)' },
          { transform: 'scale(1)' },
        ],
        { duration, easing: bezier, fill: 'forwards' }
      ).finished;

    default:
      return Promise.resolve();
  }
}

